const data = ($input.first().json?.data || $input.first().json) || {};
const fileName = $('Google Drive Trigger').item.json.name;
const fileId   = $('Google Drive Trigger').item.json.id;

const cleanNum = v => parseFloat(String(v || 0).replace(/[^0-9.]/g, '')) || 0;
const grandTotal = cleanNum(data.grandTotal);
const subtotal   = cleanNum(data.subtotal);
const discount   = cleanNum(data.discountAmount);
const shipping   = cleanNum(data.shippingCost);
const tax        = cleanNum(data.taxAmount);
const fmt = n => '$' + n.toLocaleString('en-US', {minimumFractionDigits:2, maximumFractionDigits:2});
const grandTotalFormatted = fmt(grandTotal);
const subtotalFormatted   = fmt(subtotal);
const shippingFormatted   = fmt(shipping);
const taxFormatted        = fmt(tax);
const discountText = discount > 0 ? `${fmt(discount)} (${data.discountPercent || 0}%)` : 'None';
const warrantyText = data.warrantyMonths ? `${data.warrantyMonths} months` : (data.warrantyDetails || 'N/A');

let validityStatus = 'Valid'; let validityEmoji = '✅';
if (data.validUntil) {
  const days = Math.ceil((new Date(data.validUntil) - new Date()) / (1000*60*60*24));
  if (days < 0)        { validityStatus = 'Expired';       validityEmoji = '❌'; }
  else if (days <= 7)  { validityStatus = 'Expiring Soon'; validityEmoji = '⚠️'; }
}

const deliveryTimeline = data.deliveryDays ? `${data.deliveryDays} days` : (data.deliveryTerms || 'N/A');
const itemsList = data.lineItemsList || 'N/A';

return [{ json: {
  vendorName:    data.vendorName    || 'Unknown',
  vendorContact: data.vendorContact || 'N/A',
  vendorEmail:   data.vendorEmail   || 'N/A',
  quoteNumber:   data.quoteNumber   || 'N/A',
  quoteDate:     data.quoteDate     || 'N/A',
  validUntil:    data.validUntil    || 'N/A',
  validityStatus, validityEmoji,
  quoteStatus:   validityStatus,
  itemCount:     parseInt(data.itemCount) || 0,
  itemsList, lineItemsList: itemsList,
  subtotal, subtotalFormatted,
  discountAmount: discount, discountText,
  shippingCost: shipping, shippingFormatted,
  taxAmount: tax, taxFormatted,
  grandTotal, grandTotalFormatted,
  currency:      data.currency      || 'USD',
  deliveryDays:  parseInt(data.deliveryDays) || 0,
  deliveryTimeline,
  paymentTerms:  data.paymentTerms  || 'N/A',
  warrantyMonths: parseInt(data.warrantyMonths) || 0,
  warrantyText,
  specialConditions: data.specialConditions || 'None',
  fileName, fileId,
  processedAt: new Date().toISOString()
}}];

